mapper.select:
SELECT fixed_id, user_id, vehicle_number, visitor_name, purpose, start_date, end_date, created_at, is_deleted, deleted_at FROM fixed_visitor_vehicle WHERE user_id = #{userId} AND is_deleted = 0
AND vehicle_number LIKE CONCAT('%', #{vehicleNumber}, '%')
ORDER BY created_at DESC LIMIT #{startIdx}, #{size}

SELECT COUNT(*) FROM fixed_visitor_vehicle
WHERE user_id = #{userId}
  AND is_deleted = 0

SELECT f.fixed_id, f.user_id, f.vehicle_number, f.visitor_name, f.purpose, f.start_date, f.end_date, f.created_at, u.name AS user_name, h.dong, h.ho FROM fixed_visitor_vehicle f JOIN user u ON f.user_id = u.user_id JOIN household h ON u.household_id = h.household_id WHERE f.is_deleted = 0
AND f.vehicle_number LIKE CONCAT('%', #{vehicleNumber}, '%')
AND h.dong = #{dong}
ORDER BY f.created_at DESC LIMIT #{startIdx}, #{size}

SELECT COUNT(*) FROM fixed_visitor_vehicle f JOIN user u ON f.user_id = u.user_id JOIN household h ON u.household_id = h.household_id WHERE f.is_deleted = 0
AND f.vehicle_number LIKE CONCAT('%', #{vehicleNumber}, '%')
AND h.dong = #{dong}

SELECT COUNT(*) FROM fixed_visitor_vehicle
WHERE is_deleted = 0
    AND YEAR(created_at) = #{year}
  AND MONTH(created_at) = #{month}
